import { useParams, useNavigate } from 'react-router-dom';
import api from '../data/api';

const diffColors = { easy: '#22c55e', medium: '#f59e0b', hard: '#ef4444' };
const levelOrder = ['beginner', 'intermediate', 'advanced'];
const levelColors = { beginner: '#22c55e', intermediate: '#f59e0b', advanced: '#ef4444' };

export default function CoursePage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [course, setCourse] = useState(null);
  const [activeLevel, setActiveLevel] = useState('beginner');
  const [activeTab, setActiveTab] = useState('problems');
  const [progress, setProgress] = useState(null);
  const [selectedTopic, setSelectedTopic] = useState(null);

  useEffect(() => {
    api.get(`/courses/${id}`).then(r => setCourse(r.data));
    api.get(`/progress/${id}`).then(r => setProgress(r.data)).catch(() => {});
  }, [id]);

  if (!course) return <Loader />;
  const level = course.levels.find(l => l.name === activeLevel);
  const solved = progress?.solvedProblems || [];
  const completed = progress?.completedTopics || [];

  return (
    <div style={{ minHeight: '100vh', background: '#0f172a', color: '#e2e8f0' }}>
      {/* Header */}
      <div style={{ background: '#111827', borderBottom: '1px solid #1f2937', padding: '1.5rem 2rem' }}>
        <div style={{ maxWidth: '1000px', margin: '0 auto' }}>
          <button onClick={() => navigate('/')} style={{ background: 'none', border: 'none', color: '#6b7280', cursor: 'pointer', fontSize: '0.85rem', marginBottom: '1rem', padding: 0 }}>← Back to Courses</button>
          <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
            <span style={{ fontSize: '2.5rem' }}>{course.icon}</span>
            <div>
              <h1 style={{ fontSize: '1.6rem', fontWeight: 800, color: '#fff', margin: 0 }}>{course.title}</h1>
              <p style={{ color: '#6b7280', margin: '0.2rem 0 0', fontSize: '0.9rem' }}>{course.description}</p>
            </div>
          </div>
          {/* Level Tabs */}
          <div style={{ display: 'flex', gap: '0.5rem', marginTop: '1.5rem' }}>
            {levelOrder.map(l => (
              <button key={l}
                onClick={() => setActiveLevel(l)}
                style={{ padding: '0.5rem 1.25rem', borderRadius: '8px', border: `1px solid ${activeLevel === l ? levelColors[l] : '#374151'}`, cursor: 'pointer', fontSize: '0.88rem', fontWeight: 600, background: activeLevel === l ? levelColors[l] + '22' : 'transparent', color: activeLevel === l ? levelColors[l] : '#6b7280' }}>
                {l.charAt(0).toUpperCase() + l.slice(1)}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ maxWidth: '1000px', margin: '0 auto', padding: '2rem' }}>
        {/* Content Tabs */}
        <div style={{ display: 'flex', gap: '0', marginBottom: '1.5rem', background: '#1f2937', borderRadius: '10px', padding: '0.3rem', width: 'fit-content' }}>
          {['problems', 'topics', 'assignments', 'quiz'].map(tab => (
            <button key={tab}
              onClick={() => setActiveTab(tab)}
              style={{ padding: '0.5rem 1.2rem', borderRadius: '8px', border: 'none', cursor: 'pointer', fontSize: '0.88rem', fontWeight: 600, background: activeTab === tab ? '#7c6af7' : 'transparent', color: activeTab === tab ? '#fff' : '#6b7280', transition: 'all 0.15s' }}>
              {tab === 'problems' ? '🧩 Problems' : tab === 'topics' ? '📚 Topics' : tab === 'assignments' ? '📝 Assignments' : '🎯 Quiz'}
            </button>
          ))}
        </div>

        {/* Problems Tab */}
        {activeTab === 'problems' && level && (
          <div>
            <div style={{ color: '#6b7280', fontSize: '0.85rem', marginBottom: '1rem' }}>{level.problems.length} problems</div>
            <div style={{ background: '#1f2937', borderRadius: '12px', overflow: 'hidden', border: '1px solid #374151' }}>
              <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr', padding: '0.75rem 1.25rem', borderBottom: '1px solid #374151', color: '#4b5563', fontSize: '0.8rem', fontWeight: 600, textTransform: 'uppercase' }}>
                <span>Title</span><span>Difficulty</span><span>Status</span>
              </div>
              {level.problems.map((p, i) => (
                <div key={p._id}
                  onClick={() => navigate(`/problem/${id}/${activeLevel}/${p._id}`)}
                  style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr', padding: '1rem 1.25rem', borderBottom: i < level.problems.length - 1 ? '1px solid #1f2937' : 'none', cursor: 'pointer', transition: 'background 0.15s' }}
                  onMouseEnter={e => e.currentTarget.style.background = '#374151'}
                  onMouseLeave={e => e.currentTarget.style.background = 'transparent'}>
                  <span style={{ color: '#e2e8f0', fontWeight: 500, fontSize: '0.92rem' }}>{i + 1}. {p.title}</span>
                  <span style={{ color: diffColors[p.difficulty], fontWeight: 600, fontSize: '0.82rem' }}>{p.difficulty}</span>
                  <span style={{ fontSize: '0.82rem' }}>{solved.includes(p._id) ? <span style={{ color: '#22c55e' }}>✓ Solved</span> : <span style={{ color: '#4b5563' }}>— Todo</span>}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Topics Tab */}
        {activeTab === 'topics' && level && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
            {level.topics.map(t => (
              <div key={t._id}
                onClick={() => setSelectedTopic(selectedTopic?._id === t._id ? null : t)}
                style={{ background: '#1f2937', border: `1px solid ${selectedTopic?._id === t._id ? '#7c6af7' : '#374151'}`, borderRadius: '12px', overflow: 'hidden', cursor: 'pointer' }}>
                <div style={{ padding: '1rem 1.25rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                    <span style={{ color: completed.includes(t._id) ? '#22c55e' : '#4b5563', fontSize: '1rem' }}>{completed.includes(t._id) ? '✓' : '○'}</span>
                    <span style={{ color: '#e2e8f0', fontWeight: 600 }}>{t.title}</span>
                  </div>
                  <span style={{ color: '#6b7280', fontSize: '0.8rem' }}>{selectedTopic?._id === t._id ? '▲' : '▼'}</span>
                </div>
                {selectedTopic?._id === t._id && (
                  <div style={{ padding: '0 1.25rem 1.25rem', borderTop: '1px solid #374151' }}>
                    <p style={{ color: '#9ca3af', lineHeight: 1.7, marginTop: '1rem', fontSize: '0.92rem' }}>{t.explanation}</p>
                    {t.codeExample && (
                      <pre style={{ background: '#0f172a', border: '1px solid #374151', borderRadius: '8px', padding: '1rem', color: '#a5f3fc', fontFamily: 'monospace', fontSize: '0.85rem', overflowX: 'auto', marginTop: '1rem', whiteSpace: 'pre-wrap' }}>{t.codeExample}</pre>
                    )}
                    <button
                      onClick={async e => { e.stopPropagation(); await api.post('/progress/topic', { courseId: id, topicId: t._id, level: activeLevel, totalTopics: level.topics.length }); setProgress(p => ({ ...p, completedTopics: [...(p?.completedTopics || []), t._id] })); }}
                      style={{ marginTop: '1rem', padding: '0.5rem 1.2rem', background: '#7c6af7', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 600, fontSize: '0.85rem' }}>
                      {completed.includes(t._id) ? '✓ Completed' : 'Mark Complete'}
                    </button>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        {/* Assignments Tab */}
        {activeTab === 'assignments' && level && (
          <div>
            {(!level.assignments || level.assignments.length === 0) ? (
              <div style={{ color: '#4b5563', textAlign: 'center', padding: '3rem', background: '#1f2937', borderRadius: '12px' }}>No assignments for this level yet.</div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {level.assignments.map((a, i) => (
                  <div key={a._id} style={{ background: '#1f2937', border: '1px solid #374151', borderRadius: '12px', padding: '1.5rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '0.75rem' }}>
                      <div>
                        <span style={{ color: '#6b7280', fontSize: '0.8rem', fontWeight: 600 }}>Assignment {i + 1}</span>
                        <h3 style={{ color: '#f1f5f9', fontWeight: 700, margin: '0.2rem 0', fontSize: '1rem' }}>{a.title}</h3>
                      </div>
                      <span style={{ color: diffColors[a.difficulty], background: diffColors[a.difficulty] + '22', padding: '0.2rem 0.6rem', borderRadius: '20px', fontSize: '0.75rem', fontWeight: 700 }}>{a.difficulty}</span>
                    </div>
                    <p style={{ color: '#9ca3af', fontSize: '0.88rem', lineHeight: 1.6, marginBottom: '1rem' }}>{a.description}</p>
                    {a.hints?.length > 0 && (
                      <div style={{ background: '#0f172a', borderRadius: '8px', padding: '0.75rem 1rem', marginBottom: '1rem' }}>
                        <div style={{ color: '#f59e0b', fontWeight: 600, fontSize: '0.8rem', marginBottom: '0.4rem' }}>💡 Hints</div>
                        {a.hints.map((h, hi) => <div key={hi} style={{ color: '#9ca3af', fontSize: '0.83rem', marginBottom: '0.2rem' }}>• {h}</div>)}
                      </div>
                    )}
                    <button
                      onClick={() => navigate(`/assignment/${id}/${activeLevel}/${a._id}`)}
                      style={{ padding: '0.55rem 1.3rem', background: '#7c6af7', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 600, fontSize: '0.88rem' }}>
                      Start Assignment →
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Quiz Tab */}
        {activeTab === 'quiz' && (
          <div style={{ background: '#1f2937', border: '1px solid #374151', borderRadius: '12px', padding: '2rem', textAlign: 'center' }}>
            <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🎯</div>
            <h3 style={{ color: '#fff', fontWeight: 700, marginBottom: '0.5rem' }}>{activeLevel.charAt(0).toUpperCase() + activeLevel.slice(1)} Quiz</h3>
            <p style={{ color: '#6b7280', marginBottom: '1.5rem', fontSize: '0.9rem' }}>Test your knowledge with {level?.quiz?.length || 0} questions</p>
            <button
              onClick={() => navigate(`/quiz/${id}/${activeLevel}`)}
              style={{ padding: '0.75rem 2rem', background: '#7c6af7', color: '#fff', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 700, fontSize: '1rem' }}>
              Start Quiz →
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

function Loader() {
  return <div style={{ color: '#6b7280', padding: '3rem', textAlign: 'center', background: '#0f172a', minHeight: '100vh' }}>Loading...</div>;
}
